import math


def l2_distance(a, b):
    """Euclidean (L2) distance between two equal-length vectors."""
    return math.sqrt(sum((ai - bi) ** 2 for ai, bi in zip(a, b)))


def k_nearest(query, X_train, k):
    """Indices of the k training points closest to query (by L2)."""
    dists = [(l2_distance(query, X_train[i]), i) for i in range(len(X_train))]
    dists.sort(key=lambda pair: (pair[0], pair[1]))
    return [idx for _, idx in dists[:k]]


def knn_classify(query, X_train, y_train, k):
    """Majority-vote KNN classification."""
    neighbor_idx = k_nearest(query, X_train, k)
    votes = {}
    for idx in neighbor_idx:
        label = y_train[idx]
        votes[label] = votes.get(label, 0) + 1
    best_count = max(votes.values())
    tied = [label for label, c in votes.items() if c == best_count]
    return min(tied)


def knn_regress(query, X_train, y_train, k, weighted=False):
    """KNN regression: plain or distance-weighted average of targets."""
    neighbor_idx = k_nearest(query, X_train, k)
    if not weighted:
        return sum(y_train[i] for i in neighbor_idx) / len(neighbor_idx)
    w_sum = 0.0
    val_sum = 0.0
    for i in neighbor_idx:
        w = 1.0 / (l2_distance(query, X_train[i]) + 1e-10)
        val_sum += w * y_train[i]
        w_sum += w
    return val_sum / w_sum
